import{_ as a,o,c as r,a4 as t}from"./chunks/framework.COJ7LtHI.js";const b=JSON.parse('{"title":"Interface: SortHeaderConfig · datagrid","description":"","frontmatter":{"title":"Interface: SortHeaderConfig<T> · datagrid"},"headers":[],"relativePath":"api/datagrid/interfaces/SortHeaderConfig.md","filePath":"api/datagrid/interfaces/SortHeaderConfig.md"}'),d={name:"api/datagrid/interfaces/SortHeaderConfig.md"};function n(i,e,s,l,c,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<p><a href="./../">@jsvision/datagrid</a> / SortHeaderConfig</p><h1 id="interface-sortheaderconfig-t" tabindex="-1">Interface: SortHeaderConfig&lt;T&gt; <a class="header-anchor" href="#interface-sortheaderconfig-t" aria-label="Permalink to &quot;Interface: SortHeaderConfig\\&lt;T\\&gt;&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L34" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:34</a></p><p>Construction config for <a href="./../classes/SortHeader.html">SortHeader</a>.</p><h2 id="type-parameters" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters" aria-label="Permalink to &quot;Type Parameters&quot;">​</a></h2><h3 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h3><p><code>T</code></p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="autowidths" tabindex="-1">autoWidths <a class="header-anchor" href="#autowidths" aria-label="Permalink to &quot;autoWidths&quot;">​</a></h3><blockquote><p><strong>autoWidths</strong>: () =&gt; (<code>number</code> | <code>null</code>)[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L40" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:40</a></p><p>The memoized <code>auto</code>-width measurement (shared with the body).</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p>(<code>number</code> | <code>null</code>)[]</p><hr><h3 id="columnids" tabindex="-1">columnIds <a class="header-anchor" href="#columnids" aria-label="Permalink to &quot;columnIds&quot;">​</a></h3><blockquote><p><strong>columnIds</strong>: readonly <code>string</code>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L38" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:38</a></p><p>Column ids parallel to <code>columns</code> (index → columnId), so a click resolves to a stable id.</p><hr><h3 id="columnoffset" tabindex="-1">columnOffset? <a class="header-anchor" href="#columnoffset" aria-label="Permalink to &quot;columnOffset?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>columnOffset?</strong>: <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L92" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:92</a></p><p>This panel&#39;s start index in the global visible order (default <code>0</code>), added to a local column index so <a href="#oncolumnreorder">onColumnReorder</a> reports global visible indices. <code>0</code> for a single body.</p><hr><h3 id="columns" tabindex="-1">columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;columns&quot;">​</a></h3><blockquote><p><strong>columns</strong>: <code>Column</code>&lt;<code>T</code>&gt;[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L36" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:36</a></p><p>The engine columns (titles + sizing) — shared with the body so geometry never disagrees.</p><hr><h3 id="compact" tabindex="-1">compact? <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;compact?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>compact?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L97" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:97</a></p><p>Compact density (default <code>false</code>): drop the inter-column <code>│</code> divider, reclaiming its cell so columns pack tighter. Must match the body/quick-filter setting so header and body stay column-aligned.</p><hr><h3 id="filterable" tabindex="-1">filterable? <a class="header-anchor" href="#filterable" aria-label="Permalink to &quot;filterable?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>filterable?</strong>: <code>boolean</code>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L102" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:102</a></p><p>Per-column filterability, parallel to <code>columns</code> (index → filterable). A <code>false</code> column shows <strong>no</strong> funnel and its funnel cell is not hit-testable. Omit to make every column filterable.</p><hr><h3 id="filtermodel" tabindex="-1">filterModel <a class="header-anchor" href="#filtermodel" aria-label="Permalink to &quot;filterModel&quot;">​</a></h3><blockquote><p><strong>filterModel</strong>: <code>Signal</code>&lt;<a href="./../type-aliases/FilterModel.html"><code>FilterModel</code></a>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L48" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:48</a></p><p>The container&#39;s filter model, read to render the funnel on columns that have an active filter.</p><hr><h3 id="indent" tabindex="-1">indent <a class="header-anchor" href="#indent" aria-label="Permalink to &quot;indent&quot;">​</a></h3><blockquote><p><strong>indent</strong>: <code>Signal</code>&lt;<code>number</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L42" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:42</a></p><p>The horizontal cell offset (shared with the body — header and body pan in lockstep).</p><hr><h3 id="oncolumnautofit" tabindex="-1">onColumnAutoFit? <a class="header-anchor" href="#oncolumnautofit" aria-label="Permalink to &quot;onColumnAutoFit?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onColumnAutoFit?</strong>: (<code>columnId</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L68" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:68</a></p><p>Reports a double-click on a column&#39;s grip: the <code>columnId</code> to auto-fit to its widest visible cell. Optional — omit to disable grip auto-fit.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="columnid" tabindex="-1">columnId <a class="header-anchor" href="#columnid" aria-label="Permalink to &quot;columnId&quot;">​</a></h5><p><code>string</code></p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="oncolumnreorder" tabindex="-1">onColumnReorder? <a class="header-anchor" href="#oncolumnreorder" aria-label="Permalink to &quot;onColumnReorder?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onColumnReorder?</strong>: (<code>fromVisible</code>, <code>toVisible</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L81" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:81</a></p><p>Reports a committed column reorder (a title press-drag-drop): the <code>from</code> and <code>to</code> indices in the <strong>global visible order</strong> (this panel&#39;s local index plus <a href="#columnoffset">columnOffset</a>). The target is constrained to this panel, so <code>from</code>/<code>to</code> never cross a freeze boundary. Optional — a header without it has no reorder gesture (a title stays a plain sort click).</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="fromvisible" tabindex="-1">fromVisible <a class="header-anchor" href="#fromvisible" aria-label="Permalink to &quot;fromVisible&quot;">​</a></h5><p><code>number</code></p><h5 id="tovisible" tabindex="-1">toVisible <a class="header-anchor" href="#tovisible" aria-label="Permalink to &quot;toVisible&quot;">​</a></h5><p><code>number</code></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="oncolumnresize" tabindex="-1">onColumnResize? <a class="header-anchor" href="#oncolumnresize" aria-label="Permalink to &quot;onColumnResize?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onColumnResize?</strong>: (<code>columnId</code>, <code>width</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L63" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:63</a></p><p>Reports a live column resize (a captured drag on a column&#39;s right-edge grip): the <code>columnId</code> and the new width in cells, already clamped to the column&#39;s <code>[minWidth, maxWidth]</code>. Fired on every captured drag so the grid resizes live. Optional — a header without it has no resize grips (a sort/filter-only grid is unaffected).</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="columnid-1" tabindex="-1">columnId <a class="header-anchor" href="#columnid-1" aria-label="Permalink to &quot;columnId&quot;">​</a></h5><p><code>string</code></p><h5 id="width" tabindex="-1">width <a class="header-anchor" href="#width" aria-label="Permalink to &quot;width&quot;">​</a></h5><p><code>number</code></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onfunnelclick" tabindex="-1">onFunnelClick <a class="header-anchor" href="#onfunnelclick" aria-label="Permalink to &quot;onFunnelClick&quot;">​</a></h3><blockquote><p><strong>onFunnelClick</strong>: (<code>columnId</code>, <code>anchor</code>, <code>ev</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L56" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:56</a></p><p>Reports a funnel-cell click: the clicked <code>columnId</code>, the funnel cell&#39;s header-local anchor (for positioning the filter popup), and the <strong>live dispatch envelope</strong>. The envelope is forwarded because the focus/popup seam (<code>ev.focusView</code> / <code>ev.popupHost</code>) lives on it — the container needs it to focus the mounted popup and to let the popup&#39;s nested dropdowns open (a <code>ComboBox</code>/<code>DatePicker</code> silently no-ops without <code>ev.popupHost</code>). The <code>{x,y}</code> anchor alone is not sufficient.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="columnid-2" tabindex="-1">columnId <a class="header-anchor" href="#columnid-2" aria-label="Permalink to &quot;columnId&quot;">​</a></h5><p><code>string</code></p><h5 id="anchor" tabindex="-1">anchor <a class="header-anchor" href="#anchor" aria-label="Permalink to &quot;anchor&quot;">​</a></h5><h6 id="x" tabindex="-1">x <a class="header-anchor" href="#x" aria-label="Permalink to &quot;x&quot;">​</a></h6><p><code>number</code></p><h6 id="y" tabindex="-1">y <a class="header-anchor" href="#y" aria-label="Permalink to &quot;y&quot;">​</a></h6><p><code>number</code></p><h5 id="ev" tabindex="-1">ev <a class="header-anchor" href="#ev" aria-label="Permalink to &quot;ev&quot;">​</a></h5><p><code>DispatchEvent</code></p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onheaderclick" tabindex="-1">onHeaderClick <a class="header-anchor" href="#onheaderclick" aria-label="Permalink to &quot;onHeaderClick&quot;">​</a></h3><blockquote><p><strong>onHeaderClick</strong>: (<code>columnId</code>, <code>additive</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L46" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:46</a></p><p>Reports a header click: the clicked <code>columnId</code> and whether Ctrl was held (an additive multi-key click).</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="columnid-3" tabindex="-1">columnId <a class="header-anchor" href="#columnid-3" aria-label="Permalink to &quot;columnId&quot;">​</a></h5><p><code>string</code></p><h5 id="additive" tabindex="-1">additive <a class="header-anchor" href="#additive" aria-label="Permalink to &quot;additive&quot;">​</a></h5><p><code>boolean</code></p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onreorderstart" tabindex="-1">onReorderStart? <a class="header-anchor" href="#onreorderstart" aria-label="Permalink to &quot;onReorderStart?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onReorderStart?</strong>: () =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L87" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:87</a></p><p>Fired once, when a title press turns into a reorder drag (the pointer moved past the threshold). The container uses it to revert the sort the press triggered on mouse-down, so a drag reorders without a net sort while a plain click still sorts. Optional — pairs with <a href="#oncolumnreorder">onColumnReorder</a>.</p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="showfunnel" tabindex="-1">showFunnel? <a class="header-anchor" href="#showfunnel" aria-label="Permalink to &quot;showFunnel?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>showFunnel?</strong>: <code>boolean</code>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L109" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:109</a></p><p>Per-column always-visible funnel opt-in, parallel to <code>columns</code> (index → showFunnel). A <code>true</code> column draws its funnel at all times (muted when unfiltered, emphasized when filtered); a <code>false</code> column draws the funnel only while it has an active filter (default: a clean header otherwise). Ignored where <code>filterable</code> is <code>false</code>. Omit to default every column to <code>false</code>.</p><hr><h3 id="sort" tabindex="-1">sort <a class="header-anchor" href="#sort" aria-label="Permalink to &quot;sort&quot;">​</a></h3><blockquote><p><strong>sort</strong>: <code>Signal</code>&lt;<a href="./SortKey.html"><code>SortKey</code></a>[]&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L44" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:44</a></p><p>The container&#39;s sort model, read to render the indicators.</p><hr><h3 id="widthtick" tabindex="-1">widthTick? <a class="header-anchor" href="#widthtick" aria-label="Permalink to &quot;widthTick?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>widthTick?</strong>: () =&gt; <code>unknown</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/d52325f465d5718aed8044990a44cd974bab6184/packages/datagrid/src/sort-header.ts#L74" target="_blank" rel="noreferrer">datagrid/src/sort-header.ts:74</a></p><p>A reactive column-geometry trigger, bound for repaint so a width-override change (a live resize / auto-fit) re-apportions the header — <code>draw</code> reads widths through the column objects but does not auto-track. Omit when the grid has no resizable columns.</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>unknown</code></p>',136)])])}const p=a(d,[["render",n]]);export{b as __pageData,p as default};
